def has_unique_digits(year):
    str_year = str(year)
    length = len(str_year)
    for i in range(length):
        for j in range(i + 1, length):
            if str_year[i] == str_year[j]:
                return False
    return True

def next_unique_year(current_year):
    next_year = current_year + 1
    while True:
        if has_unique_digits(next_year):
            return next_year
        next_year += 1
